// Extrae el SQL devuelto por Claude y valida que sea un SELECT seguro
const raw = ($json.content && $json.content[0] && $json.content[0].text) || '';
let sql = String(raw).trim();
sql = sql.replace(/^```(?:sql)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
sql = sql.replace(/;\s*$/, '').trim();
if (!/^SELECT\b/i.test(sql)) {
  sql = 'SELECT NULL AS error';
}
if (/;\s*\S/.test(sql)) {
  sql = 'SELECT NULL AS error';
}
const body = ($('Webhook RAG').first().json.body) || {};
// body.usuario_id corresponde al `sub` de Auth0 (p.ej. 'auth0|abc...').
// El ms-log lo resuelve a UUID consultando la tabla `usuarios`.
return [{
  json: {
    sql,
    pregunta: body.pregunta || '',
    auth0_id: body.usuario_id || body.auth0_id || null,
    email: body.email || null
  }
}];

// Agrupa el resultado de Postgres en un unico contexto JSON para el LLM.
// Filtra el item vacio que Postgres emite (alwaysOutputData) cuando no hay filas.
const rows = $input.all()
  .map(it => it.json)
  .filter(r => r && Object.keys(r).length > 0);
const sanit = $('Sanitizar SQL').first().json;
return [{
  json: {
    pregunta: sanit.pregunta || '',
    auth0_id: sanit.auth0_id || null,
    email: sanit.email || null,
    sql: sanit.sql || '',
    rows,
    filas: rows.length,
    contextoJson: JSON.stringify(rows, null, 2)
  }
}];

// Extrae el texto final de Claude y arma el payload de respuesta + log.
// El identificador del usuario llega como auth0_id (sub del JWT); el ms-log lo resolverá a UUID.
const raw = ($json.content && $json.content[0] && $json.content[0].text) || '';
const respuesta = String(raw).trim();
const ctx = $('Componer contexto').first().json;
return [{
  json: {
    pregunta: ctx.pregunta,
    respuesta,
    sql: ctx.sql,
    filas: ctx.filas || 0,
    auth0_id: ctx.auth0_id || null,
    email: ctx.email || null
  }
}];
